using System.Collections.Generic;

namespace NMSE.Data;

/// <summary>
/// Provides technology adjacency data for computing synergy borders in inventory grids.
/// Items with the same BaseStatType are considered adjacent/linked.
/// </summary>
public static class TechAdjacencyDatabase
{
    /// <summary>Adjacency information for a single technology item.</summary>
    public class TechAdjacencyInfo
    {
        /// <summary>Base stat type ordinal used to determine adjacency grouping.</summary>
        public int BaseStatType { get; set; }
        /// <summary>Technology category ordinal for this item.</summary>
        public int TechnologyCategory { get; set; }
        /// <summary>Hex colour string for the adjacency link border (e.g. "#44FDFF").</summary>
        public string LinkColourHex { get; set; } = "#FFFFFF";
    }

