    /// <summary>
    /// Gets adjacency info for an item ID, handling ^ prefix and #variant suffix.
    /// </summary>
    public static TechAdjacencyInfo? GetAdjacencyInfo(string itemId)
    {
        if (string.IsNullOrEmpty(itemId)) return null;
        // Strip ^ prefix
        string id = itemId.StartsWith("^") ? itemId.Substring(1) : itemId;
        // Strip #variant suffix
        int hashIdx = id.IndexOf('#');
        if (hashIdx >= 0) id = id.Substring(0, hashIdx);
        Dictionary.TryGetValue(id, out var info);
        return info;
    }

