    /// <summary>Returns the canonical link colour hex string for a given base stat type.</summary>
    /// <param name="baseStatType">The base stat type ordinal.</param>
    /// <returns>A hex colour string, or "#FFFFFF" if unknown.</returns>
    public static string GetBaseStatTypeColour(int baseStatType)
    {
        return _baseStatTypeColours.TryGetValue(baseStatType, out var colour) ? colour : "#FFFFFF";
